import subprocess
import sys
import base64
import os

IMAGES_B64 = {
    "kaito": ("Kaito Độ Mixi", """"""),
    "meo": ("Mèo", """"""),
    "anime": ("Anime", """"""),
    "cho_wtdd": ("Chó WTDD", """"""),
}


TARGET_DPI = 700

TMP_DIR = "/data/local/tmp/wallpapers_tmp"


def run_su(cmd: str) -> tuple[int, str, str]:
    proc = subprocess.run(["su", "-c", cmd], capture_output=True, text=True, timeout=15)
    return proc.returncode, proc.stdout.strip(), proc.stderr.strip()


def decode_image(key: str) -> str:
    """Giải mã base64 thành file ảnh tạm, trả về path."""
    _, b64data = IMAGES_B64[key]
    raw = base64.b64decode(b64data)
    out_path = f"{TMP_DIR}/{key}.png"

    os.makedirs(TMP_DIR, exist_ok=True)
    with open(out_path, "wb") as f:
        f.write(raw)

    run_su(f"chmod 644 '{out_path}'")
    return out_path


def set_wallpaper(image_path: str) -> bool:
    code, out, err = run_su(f"cmd wallpaper set '{image_path}'")
    if code == 0 and "error" not in err.lower():
        return True

    code, _, err2 = run_su(
        f"am start -a android.intent.action.ATTACH_DATA "
        f"-c android.intent.category.DEFAULT "
        f"-d 'file://{image_path}' -t 'image/*'"
    )
    if code == 0:
        return True

    target = "/data/system/users/0/wallpaper"
    code, _, err3 = run_su(f"cp '{image_path}' '{target}' && chmod 644 '{target}'")
    if code == 0:
        run_su("am force-stop com.android.systemui")
        run_su("am broadcast -a android.intent.action.WALLPAPER_CHANGED")
        return True

    print(f"Lỗi set wallpaper: {err or err2 or err3}", file=sys.stderr)
    return False


def set_dpi(dpi: int) -> bool:
    code, out, err = run_su(f"wm density {dpi}")
    if code == 0:
        return True
    print(f"Lỗi set DPI: {err or out}", file=sys.stderr)
    return False


def show_menu() -> None:
    print("Chọn ảnh nền:")
    for i, key in enumerate(IMAGES_B64.keys(), start=1):
        label, _ = IMAGES_B64[key]
        print(f"  {i}. {label}")


def main():
    show_menu()
    choice = input("Nhập số: ").strip()

    keys = list(IMAGES_B64.keys())
    idx = int(choice) - 1 if choice.isdigit() else -1

    if idx < 0 or idx >= len(keys):
        print("Lựa chọn không hợp lệ.")
        return

    key = keys[idx]
    label, _ = IMAGES_B64[key]
    print(f"Đang giải mã ảnh: {label} ...")

    try:
        image_path = decode_image(key)
    except Exception as e:
        print(f"Lỗi giải mã ảnh: {e}", file=sys.stderr)
        return

    print(f"Đang đổi nền sang: {label} ...")
    wp_ok = set_wallpaper(image_path)
    print("Đổi nền: " + ("THÀNH CÔNG" if wp_ok else "THẤT BẠI"))

    print(f"Đang chỉnh DPI lên {TARGET_DPI} ...")
    dpi_ok = set_dpi(TARGET_DPI)
    print("Chỉnh DPI: " + ("THÀNH CÔNG" if dpi_ok else "THẤT BẠI"))

    if wp_ok and dpi_ok:
        print("\n Hoàn tất, mọi thứ đã áp dụng.")
    else:
        print("\n Có bước thất bại, xem lỗi phía trên.")


if __name__ == "__main__":
    main()
